<div class="d-flex justify-content-between align-items-center mb-4"><div><p class="text-uppercase fw-semibold archive-kicker-dark mb-1">Production readiness</p><h1 class="h2 mb-0">Operations</h1></div><a class="btn btn-outline-secondary" href="<?= e(url('/admin')) ?>">Dashboard</a></div>
<div class="row g-3 mb-4"><?php foreach (['critical_24h'=>'Critical events (24h)','errors_24h'=>'Errors (24h)','pending_payments'=>'Pending payments','open_disputes'=>'Open disputes','pending_deletions'=>'Pending deletions'] as $key=>$label): ?><div class="col-md-4 col-xl"><div class="archive-card p-3 h-100"><div class="small text-muted"><?= e($label) ?></div><div class="h2 mb-0"><?= e((string)$operations[$key]) ?></div></div></div><?php endforeach; ?></div>
<div class="row g-4"><div class="col-lg-5"><div class="archive-card p-4 h-100"><h2 class="h5">Backup status</h2><?php if($operations['last_backup']):?><div class="text-success fw-semibold"><?= e(ucfirst($operations['last_backup']['status'])) ?></div><div class="small"><?= e($operations['last_backup']['filename']) ?><br><?= e($operations['last_backup']['completed_at']) ?><br>SHA-256 <?= e($operations['last_backup']['checksum_sha256']) ?></div><?php else:?><div class="alert alert-warning mb-0">No completed backup is recorded.</div><?php endif;?><h2 class="h5 mt-4">Applied migrations</h2><?php foreach($operations['migrations'] as $migration):?><div class="small border-bottom py-2"><strong><?= e($migration['version']) ?></strong><br><?= e($migration['applied_at']) ?></div><?php endforeach;?></div></div><div class="col-lg-7"><div class="archive-card p-4"><h2 class="h5">Recent system events</h2><?php if($operations['recent_events']===[]):?><p class="text-muted mb-0">No events recorded.</p><?php else:?><div class="table-responsive"><table class="table table-sm"><thead><tr><th>Time</th><th>Severity</th><th>Event</th><th>Message</th></tr></thead><tbody><?php foreach($operations['recent_events'] as $event):?><tr><td class="small"><?= e($event['occurred_at']) ?></td><td><span class="badge text-bg-<?= in_array($event['severity'],['error','critical'],true)?'danger':'secondary' ?>"><?= e($event['severity']) ?></span></td><td><?= e($event['event_type']) ?></td><td class="small"><?= e($event['message']) ?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></div></div></div>

<div class="archive-card p-4 mt-4"><h2 class="h5">Resolve operational events</h2><?php foreach($operations['recent_events'] as $event):?><?php if(empty($event['resolved_at'])&&in_array($event['severity'],['error','critical'],true)):?><form class="border rounded p-3 mb-2" method="post" action="<?= e(url('/admin/operations/resolve?id='.(int)$event['id'])) ?>"><div class="small mb-2"><strong>#<?= e((string)$event['id']) ?> <?= e($event['event_type']) ?></strong> — <?= e($event['message']) ?></div><div class="input-group"><input class="form-control" name="resolution" minlength="10" maxlength="1000" placeholder="Root cause and corrective action" required><button class="btn btn-outline-success">Mark resolved</button></div></form><?php endif;?><?php endforeach;?></div>
